interface MockRes {
  statusCode: number;
  headers?: Record<string, string>;
  on: jest.Mock;
}

function buildMockRes(statusCode: number, body: string, headers?: Record<string, string>): MockRes {
  const res: MockRes = {
    statusCode,
    headers,
    on: jest.fn((event: string, handler: (...args: unknown[]) => void) => {
      if (event === 'data') handler(body);
      if (event === 'end') handler();
      return res;
    }),
  };
  return res;
}

const wwwAuth = 'Bearer realm="https://quay.io/v2/auth",service="quay.io"';

/**
 * Mock the challenge-response flow (3 calls):
 * 1. catalog → 401 with WWW-Authenticate
 * 2. token exchange → { token: jwt }
 * 3. catalog retry → { repositories: repos }
 */
function mockChallengeFlow(repos: string[], jwt = 'mock-jwt'): void {
  mockHttpsGet
    .mockImplementationOnce((_url: unknown, _opts: unknown, callback: (res: MockRes) => void) => {
      callback(
        buildMockRes(401, JSON.stringify({ errors: [{ code: 'UNAUTHORIZED' }] }), {
          'www-authenticate': wwwAuth,
        }),
      );
      return { on: jest.fn() };
    })
    .mockImplementationOnce((_url: unknown, _opts: unknown, callback: (res: MockRes) => void) => {
      callback(buildMockRes(200, JSON.stringify({ token: jwt })));
      return { on: jest.fn() };
    })
    .mockImplementationOnce((_url: unknown, _opts: unknown, callback: (res: MockRes) => void) => {
      callback(buildMockRes(200, JSON.stringify({ repositories: repos })));
      return { on: jest.fn() };
    });
}

